<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Maze Bot Challenge</title>
<style>
  *{margin:0;padding:0;box-sizing:border-box}
  body{background:#0b0b1a;color:#e0e0e0;font-family:'Segoe UI',system-ui,sans-serif;display:flex;flex-direction:column;align-items:center;min-height:100vh;padding:20px}
  h1{margin-bottom:12px;color:#ff6b6b;font-size:22px;text-shadow:0 0 12px rgba(255,107,107,.4)}
  #hud{display:flex;gap:28px;margin-bottom:12px;align-items:center;background:rgba(255,255,255,.06);padding:10px 24px;border-radius:8px;border:1px solid rgba(255,255,255,.08)}
  #hud span{font-size:15px;font-weight:600}
  #completed{color:#4ecdc4}
  #timer{color:#ffe66d}
  #reset{padding:8px 20px;background:#ff6b6b;color:#fff;border:none;border-radius:6px;cursor:pointer;font-size:14px;font-weight:600;transition:all .2s}
  #reset:hover{background:#ee5a5a;transform:scale(1.05)}
  #maze{border:2px solid #ff6b6b;border-radius:4px;box-shadow:0 0 30px rgba(255,107,107,.15)}
</style>
</head>
<body>
<h1>🤖 Maze Bot Challenge</h1>
<div id="hud">
  <span id="completed">Completed: 0 / 24</span>
  <span id="timer">Time: 0.0s</span>
  <button id="reset">Reset</button>
</div>
<canvas id="maze" width="420" height="420"></canvas>
<script>
(function(){
  "use strict";
  const COLS=21, ROWS=21, CELL=20, NUM_BOTS=24;
  const canvas=document.getElementById("maze");
  const ctx=canvas.getContext("2d");
  const completedEl=document.getElementById("completed");
  const timerEl=document.getElementById("timer");
  const resetBtn=document.getElementById("reset");

  let maze=null, path=null, bots=[], completedCount=0, startTime=0, animId=null, running=false;

  /* ---- Maze generation (recursive backtracking) ---- */
  function generateMaze(){
    var grid=[];
    for(var y=0;y<ROWS;y++){grid[y]=[];for(var x=0;x<COLS;x++) grid[y][x]={top:true,right:true,bottom:true,left:true};}
    var visited=Array.from({length:ROWS},function(){return Array(COLS).fill(false);});
    var stack=[{x:0,y:0}]; visited[0][0]=true;
    while(stack.length>0){
      var cur=stack[stack.length-1];
      var nb=[];
      if(cur.y>0&&!visited[cur.y-1][cur.x]) nb.push({x:cur.x,y:cur.y-1,d:"top"});
      if(cur.x<COLS-1&&!visited[cur.y][cur.x+1]) nb.push({x:cur.x+1,y:cur.y,d:"right"});
      if(cur.y<ROWS-1&&!visited[cur.y+1][cur.x]) nb.push({x:cur.x,y:cur.y+1,d:"bottom"});
      if(cur.x>0&&!visited[cur.y][cur.x-1]) nb.push({x:cur.x-1,y:cur.y,d:"left"});
      if(nb.length>0){
        var n=nb[Math.floor(Math.random()*nb.length)];
        if(n.d==="top"){grid[cur.y][cur.x].top=false;grid[n.y][n.x].bottom=false;}
        if(n.d==="right"){grid[cur.y][cur.x].right=false;grid[n.y][n.x].left=false;}
        if(n.d==="bottom"){grid[cur.y][cur.x].bottom=false;grid[n.y][n.x].top=false;}
        if(n.d==="left"){grid[cur.y][cur.x].left=false;grid[n.y][n.x].right=false;}
        visited[n.y][n.x]=true; stack.push({x:n.x,y:n.y});
      } else { stack.pop(); }
    }
    return grid;
  }

  /* ---- BFS shortest path ---- */
  function bfs(start,end){
    var q=[start], seen=new Set(), par=new Map();
    seen.add(start.x+","+start.y);
    while(q.length>0){
      var c=q.shift();
      if(c.x===end.x&&c.y===end.y){
        var p=[]; var n=c;
        while(n){p.unshift(n); n=par.get(n.x+","+n.y);}
        return p;
      }
      var cell=maze[c.y][c.x], dirs=[];
      if(!cell.top) dirs.push({x:c.x,y:c.y-1});
      if(!cell.right) dirs.push({x:c.x+1,y:c.y});
      if(!cell.bottom) dirs.push({x:c.x,y:c.y+1});
      if(!cell.left) dirs.push({x:c.x-1,y:c.y});
      for(var i=0;i<dirs.length;i++){
        var k=dirs[i].x+","+dirs[i].y;
        if(!seen.has(k)){seen.add(k); par.set(k,c); q.push(dirs[i]);}
      }
    }
    return [];
  }

  /* ---- Init bots ---- */
  function initBots(){
    bots=[]; completedCount=0;
    for(var i=0;i<NUM_BOTS;i++){
      bots.push({
        x:0, y:0,
        pathIndex:0,
        delay:Math.floor(Math.random()*150),
        completed:false,
        color:"hsl("+((i*360/NUM_BOTS)|0)+",80%,60%)",
        phase:Math.random()*Math.PI*2
      });
    }
  }

  /* ---- Tick (synchronous) ---- */
  function tick(n){
    for(var s=0;s<n;s++){
      for(var i=0;i<bots.length;i++){
        var b=bots[i];
        if(b.completed) continue;
        if(b.delay>0){ b.delay--; }
        else{
          b.pathIndex++;
          if(b.pathIndex>=path.length){ b.completed=true; completedCount++; }
          else{ b.x=path[b.pathIndex].x; b.y=path[b.pathIndex].y; }
        }
      }
    }
    updateHUD();
  }

  /* ---- HUD ---- */
  function updateHUD(){
    completedEl.textContent="Completed: "+completedCount+" / "+NUM_BOTS;
    var el=(Date.now()-startTime)/1000;
    timerEl.textContent="Time: "+el.toFixed(1)+"s";
  }

  /* ---- Render ---- */
  function render(){
    ctx.fillStyle="#0f0f23";
    ctx.fillRect(0,0,canvas.width,canvas.height);

    /* cells + walls */
    for(var y=0;y<ROWS;y++){
      for(var x=0;x<COLS;x++){
        var px=x*CELL, py=y*CELL;
        ctx.fillStyle="#16213e";
        ctx.fillRect(px,py,CELL,CELL);
        var c=maze[y][x];
        ctx.strokeStyle="#e94560";
        ctx.lineWidth=2;
        if(c.top){ctx.beginPath();ctx.moveTo(px,py);ctx.lineTo(px+CELL,py);ctx.stroke();}
        if(c.right){ctx.beginPath();ctx.moveTo(px+CELL,py);ctx.lineTo(px+CELL,py+CELL);ctx.stroke();}
        if(c.bottom){ctx.beginPath();ctx.moveTo(px,py+CELL);ctx.lineTo(px+CELL,py+CELL);ctx.stroke();}
        if(c.left){ctx.beginPath();ctx.moveTo(px,py);ctx.lineTo(px,py+CELL);ctx.stroke();}
      }
    }

    /* spawn highlight */
    ctx.fillStyle="rgba(78,205,196,.25)";
    ctx.fillRect(0,0,CELL,CELL);
    /* exit highlight */
    ctx.fillStyle="rgba(255,107,107,.25)";
    ctx.fillRect((COLS-1)*CELL,(ROWS-1)*CELL,CELL,CELL);

    /* bots */
    var t=Date.now()/1000;
    for(var i=0;i<bots.length;i++){
      var b=bots[i];
      if(b.completed) continue;
      var cx=b.x*CELL+CELL/2, cy=b.y*CELL+CELL/2;
      var pulse=1+0.35*Math.sin(t*3+b.phase);
      var r=4.5*pulse;
      /* glow */
      ctx.beginPath();ctx.arc(cx,cy,r+3,0,Math.PI*2);
      ctx.fillStyle="rgba(255,255,255,.08)";ctx.fill();
      /* body */
      ctx.beginPath();ctx.arc(cx,cy,r,0,Math.PI*2);
      ctx.fillStyle=b.color;ctx.fill();
      /* highlight */
      ctx.beginPath();ctx.arc(cx-1,cy-1,r*0.35,0,Math.PI*2);
      ctx.fillStyle="rgba(255,255,255,.45)";ctx.fill();
    }
  }

  /* ---- Game loop ---- */
  function gameLoop(){
    if(!running) return;
    tick(1);
    render();
    animId=requestAnimationFrame(gameLoop);
  }

  /* ---- Reset ---- */
  function reset(){
    running=false;
    if(animId) cancelAnimationFrame(animId);
    maze=generateMaze();
    path=bfs({x:0,y:0},{x:COLS-1,y:ROWS-1});
    initBots();
    startTime=Date.now();
    updateHUD();
    render();
    running=true;
    animId=requestAnimationFrame(gameLoop);
  }

  /* ---- Expose API ---- */
  window.game={
    get bots(){return bots;},
    get completed(){return completedCount;},
    get elapsedMs(){return Date.now()-startTime;},
    tick:tick,
    reset:reset
  };

  resetBtn.addEventListener("click",reset);
  reset();
})();
</script>
</body>
</html>
